// Extract token from response
const response = pm.response.json();

if (response.json && response.json.username) {
    // Simulate token extraction
    const mockToken = 'bearer_' + Date.now();
    pm.environment.set('auth_token', mockToken);
    console.log('Auth token set:', mockToken);

    pm.test('Authentication successful', () => {
        pm.expect(pm.response.status).to.equal(200);
    });
}

pm.test('Profile retrieved', () => {
    pm.expect(pm.response.status).to.equal(200);
});

console.log('Profile request completed with token:', pm.environment.get('auth_token'));
